BEGIN TRANSACTION;

drop schema if exists "laboratorio" cascade;

create schema "laboratorio";
set search_path to "laboratorio";

CREATE TABLE STUDENTE (
    Matricola VARCHAR(20) PRIMARY KEY,
    Nome VARCHAR(255),
    Cognome VARCHAR(255),
    Genere CHAR(1),
    DataN DATE,
    LuogoN VARCHAR(255),
    Residenza VARCHAR(255),
    Telefono VARCHAR(20),
    CorsodiLaurea VARCHAR(255)
);

CREATE TABLE DIPENDENTE (
    MatricolaD VARCHAR(20) PRIMARY KEY,
    Nome VARCHAR(255),
    Cognome VARCHAR(255),
    Ruolo VARCHAR(100),
    Email VARCHAR(255),
    Ufficio VARCHAR(100),
    Telefono VARCHAR(20)
);

CREATE TABLE DOCENTE (
    MatricolaD VARCHAR(20) PRIMARY KEY REFERENCES DIPENDENTE(MatricolaD)
);

CREATE TABLE LABORATORIO (
    CodLabo VARCHAR(50) PRIMARY KEY,
    Edificio VARCHAR(100),
    NumLocale VARCHAR(20),
    Responsabile VARCHAR(20) REFERENCES DIPENDENTE(MatricolaD),
    UNIQUE (Edificio, NumLocale),
    UNIQUE (Responsabile)
);

CREATE TABLE POSTAZIONE (
    NumP INTEGER,
    CodLabo VARCHAR(50) REFERENCES LABORATORIO(CodLabo),
    PRIMARY KEY (NumP, CodLabo)
);

CREATE TABLE RISORSA (
    CodRis VARCHAR(50) PRIMARY KEY,
    ConAutorizzazione BOOLEAN,
    NumP INTEGER,
    CodLabo VARCHAR(50),
    FOREIGN KEY (NumP, CodLabo) REFERENCES POSTAZIONE(NumP, CodLabo)
);

CREATE TABLE UTILIZZO (
    Matricola VARCHAR(20) REFERENCES STUDENTE(Matricola),
    NumP INTEGER,
    CodLabo VARCHAR(50),
    Data DATE,
    OraI TIME,
    OraF TIME,
    PRIMARY KEY (Matricola, NumP, CodLabo, Data, OraI),
    FOREIGN KEY (NumP, CodLabo) REFERENCES POSTAZIONE(NumP, CodLabo)
);

CREATE TABLE INSEGNAMENTO (
    CodIns VARCHAR(50) PRIMARY KEY,
    Titolo VARCHAR(255),
    CorsodiLaurea VARCHAR(255),
    MatricolaD VARCHAR(20) REFERENCES DOCENTE(MatricolaD)
);

CREATE TABLE OCCUPA (
    CodIns VARCHAR(50) REFERENCES INSEGNAMENTO(CodIns),
    CodLabo VARCHAR(50) REFERENCES LABORATORIO(CodLabo),
    Data DATE,
    OraIn TIME,
    OraFine TIME,
    PRIMARY KEY (CodIns, CodLabo, Data, OraIn)
);

-- Fila B only: students authorized to use specific resources
CREATE TABLE AUTORIZZAZIONE (
    Matricola VARCHAR(20) REFERENCES STUDENTE(Matricola),
    CodRis VARCHAR(50) REFERENCES RISORSA(CodRis),
    Autorizzatore VARCHAR(20) REFERENCES DOCENTE(MatricolaD),
    DataScadenza DATE,
    Motivazione TEXT,
    PRIMARY KEY (Matricola, CodRis)
);

-- No INSERT statements (exam PDF source, no data instances provided)

COMMIT;

solutions:
SELECT DISTINCT MatricolaD
FROM INSEGNAMENTO NATURAL JOIN OCCUPA NATURAL JOIN RISORSA
WHERE ConAutorizzazione = TRUE;

SELECT Matricola, CodRis
FROM AUTORIZZAZIONE NATURAL JOIN RISORSA NATURAL JOIN LABORATORIO
WHERE Autorizzatore <> Responsabile;
